class Ticket(BaseModel):
    category: str  # "please pick from billing/tech_support/refund/spam/other"
    priority: str  # "one of P0/P1/P2/P3"

from typing import Literal, Annotated
from pydantic import BaseModel, Field

class KnownLabel(BaseModel):
    kind: Literal["known"] = "known"
    value: Literal["billing", "tech_support", "refund"]

class NovelLabel(BaseModel):
    kind: Literal["novel"] = "novel"
    proposed: str = Field(description="Free-text label; will be queued for taxonomy review.")

class Ticket(BaseModel):
    category: Annotated[KnownLabel | NovelLabel, Field(discriminator="kind")]
